const crypto = require('crypto');

// Inputs
const proposal_id = $json.proposal_id;
const secret = $env.N8N_SHARED_SECRET;
if (!secret) throw new Error('N8N_SHARED_SECRET is not set');

const ts = Math.floor(Date.now()/1000).toString();
const nonce = crypto.randomBytes(12).toString('base64url');
const bodyObj = { proposal_id };
const body = JSON.stringify(bodyObj);

const base = `v1:${ts}:${nonce}:${body}`;
const digest = crypto.createHmac('sha256', secret).update(base).digest('hex');
const sig = `v1=${digest}`;

return [{
  json: {
    body: bodyObj,
    headers: {
      'X-CG-Timestamp': ts,
      'X-CG-Nonce': nonce,
      'X-CG-Signature': sig,
      'Idempotency-Key': `execute:${proposal_id}`
    }
  }
}];
